import{_ as t,o,c as s,ag as a}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"AI Note Processing","description":"","frontmatter":{},"headers":[],"relativePath":"coach-notes/ai-processing.md","filePath":"coach-notes/ai-processing.md"}'),r={name:"coach-notes/ai-processing.md"};function i(n,e,c,l,h,d){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="ai-note-processing" tabindex="-1">AI Note Processing <a class="header-anchor" href="#ai-note-processing" aria-label="Permalink to &quot;AI Note Processing&quot;">​</a></h1><p>AI note processing converts free-form coaching observations into structured player-specific records. It is designed for coaches who prefer to write or dictate extended notes rather than entering observations field by field.</p><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><ol><li>Navigate to <strong>Notes hub → Process Notes with AI</strong></li><li>Type or paste your observations (up to 2,000 characters)</li><li>Select a date range for context (optional but recommended)</li><li>Tap <strong>Process Notes with AI</strong></li><li>Review results on the structured output screen</li></ol><h2 id="what-the-ai-extracts" tabindex="-1">What the AI Extracts <a class="header-anchor" href="#what-the-ai-extracts" aria-label="Permalink to &quot;What the AI Extracts&quot;">​</a></h2><p>The AI identifies:</p><ul><li>Which player each observation is about (matched to your roster)</li><li>What area of the game the observation covers (pitching, hitting, fielding, baserunning, mechanics)</li><li>Whether the observation is positive, a concern, or neutral</li><li>Whether the issue is recurring (based on previous notes in the context window)</li></ul><h2 id="results-screen" tabindex="-1">Results Screen <a class="header-anchor" href="#results-screen" aria-label="Permalink to &quot;Results Screen&quot;">​</a></h2><p>The results screen shows a card for each extracted observation:</p><ul><li><strong>Player</strong> — matched roster player (amber warning if not matched)</li><li><strong>Area</strong> — hitting, pitching, fielding, baserunning, or mechanics</li><li><strong>Observation</strong> — the structured summary</li><li><strong>Pattern</strong> — Recurring, Improving, or New (based on note history)</li></ul><p>From each card you can:</p><ul><li><strong>Save</strong> — saves as a player note</li><li><strong>Create Training Plan</strong> — opens a pre-filled training plan</li><li><strong>Skip</strong> — discards this observation</li></ul><h2 id="including-previous-notes-as-context" tabindex="-1">Including Previous Notes as Context <a class="header-anchor" href="#including-previous-notes-as-context" aria-label="Permalink to &quot;Including Previous Notes as Context&quot;">​</a></h2><p>When you select a date range the AI includes notes from that period as background context. This enables pattern detection — the same issue noted three times becomes <strong>Recurring</strong> instead of <strong>New</strong>.</p><p>Use 2-4 weeks as the standard context window. A full season can work but may surface too many resolved issues.</p><h2 id="usage-limits" tabindex="-1">Usage Limits <a class="header-anchor" href="#usage-limits" aria-label="Permalink to &quot;Usage Limits&quot;">​</a></h2><p>AI note processing counts toward your monthly AI note limit:</p><table tabindex="0"><thead><tr><th>Plan</th><th>AI Notes per Month</th></tr></thead><tbody><tr><td>Coach</td><td>50</td></tr><tr><td>Organization</td><td>200</td></tr></tbody></table><p>Each <strong>Process Notes with AI</strong> submission counts as one use regardless of how many player observations it extracts.</p>',19)])])}const p=t(r,[["render",i]]);export{g as __pageData,p as default};
